import{_ as e}from"./plugin-vue_export-helper.21dcd24c.js";import{o as r,c as a,e as i}from"./app.d1ff24bc.js";const l={},o=i('<p>\u9AD8\u5E76\u53D1\u7CFB\u7EDF\u6838\u5FC3\u6307\u6807</p><h2 id="qps-\u6BCF\u79D2\u67E5\u8BE2" tabindex="-1"><a class="header-anchor" href="#qps-\u6BCF\u79D2\u67E5\u8BE2" aria-hidden="true">#</a> QPS\uFF0C\u6BCF\u79D2\u67E5\u8BE2</h2><p>QPS\uFF1AQueries Per Second\u662F\u8861\u91CF\u4FE1\u606F\u68C0\u7D22\u7CFB\u7EDF\uFF08\u4F8B\u5982\u641C\u7D22\u5F15\u64CE\u6216\u6570\u636E\u5E93\uFF09\u5728\u4E00\u79D2\u949F\u5185\u63A5\u6536\u5230\u7684\u641C\u7D22\u6D41\u91CF\u7684\u4E00\u79CD\u5E38\u89C1\u5EA6\u91CF\u3002\u8BE5\u672F\u8BED\u5728\u4EFB\u4F55\u8BF7\u6C42-\u54CD\u5E94\u7CFB\u7EDF\u4E2D\u90FD\u5F97\u5230\u66F4\u5E7F\u6CDB\u7684\u4F7F\u7528\uFF0C\u66F4\u6B63\u786E\u5730\u79F0\u4E3A\u6BCF\u79D2\u8BF7\u6C42\u6570\uFF08RPS\uFF1ARequest Per Second\uFF09\u3002</p><h2 id="tps-\u6BCF\u79D2\u4E8B\u52A1" tabindex="-1"><a class="header-anchor" href="#tps-\u6BCF\u79D2\u4E8B\u52A1" aria-hidden="true">#</a> TPS\uFF0C\u6BCF\u79D2\u4E8B\u52A1</h2><p>TPS\uFF1A\u662FTransactions Per Second\u7684\u7F29\u5199\uFF0C\u4E5F\u5C31\u662F\u4E8B\u52A1\u6570/\u79D2\u3002\u5B83\u662F\u8F6F\u4EF6\u6D4B\u8BD5\u7ED3\u679C\u7684\u6D4B\u91CF\u5355\u4F4D\u3002\u4E00\u4E2A\u4E8B\u52A1\u662F\u6307\u4E00\u4E2A\u5BA2\u6237\u7AEF\u5411\u670D\u52A1\u5668\u53D1\u9001\u8BF7\u6C42\u7136\u540E\u670D\u52A1\u5668\u505A\u51FA\u54CD\u5E94\u7684\u8FC7\u7A0B\u3002\u5BA2\u6237\u7AEF\u5728\u53D1\u9001\u8BF7\u6C42\u65F6\u5F00\u59CB\u8BA1\u65F6\uFF0C\u6536\u5230\u670D\u52A1\u5668\u54CD\u5E94\u540E\u7ED3\u675F\u8BA1\u65F6\uFF0C\u4EE5\u6B64\u6765\u8BA1\u7B97\u4F7F\u7528\u7684\u65F6\u95F4\u548C\u5B8C\u6210\u7684\u4E8B\u52A1\u4E2A\u6570\u3002</p><p>QPS vs TPS\uFF1AQPS\u57FA\u672C\u7C7B\u4F3C\u4E8ETPS\uFF0C\u4F46\u662F\u4E0D\u540C\u7684\u662F\uFF0C\u5BF9\u4E8E\u4E00\u4E2A\u9875\u9762\u7684\u4E00\u6B21\u8BBF\u95EE\uFF0C\u5F62\u6210\u4E00\u4E2ATPS\uFF1B\u4F46\u4E00\u6B21\u9875\u9762\u8BF7\u6C42\uFF0C\u53EF\u80FD\u4EA7\u751F\u591A\u6B21\u5BF9\u670D\u52A1\u5668\u7684\u8BF7\u6C42\uFF0C\u670D\u52A1\u5668\u5BF9\u8FD9\u4E9B\u8BF7\u6C42\uFF0C\u5C31\u53EF\u8BA1\u5165\u201CQPS\u201D\u4E4B\u4E2D\u3002\u5982\uFF0C\u8BBF\u95EE\u4E00\u4E2A\u9875\u9762\u4F1A\u8BF7\u6C42\u670D\u52A1\u56682\u6B21\uFF0C\u4E00\u6B21\u8BBF\u95EE\uFF0C\u4EA7\u751F\u4E00\u4E2A\u201CT\u201D\uFF0C\u4EA7\u751F2\u4E2A\u201CQ\u201D\u3002</p><h2 id="rt-\u54CD\u5E94\u65F6\u95F4" tabindex="-1"><a class="header-anchor" href="#rt-\u54CD\u5E94\u65F6\u95F4" aria-hidden="true">#</a> RT\uFF0C\u54CD\u5E94\u65F6\u95F4</h2><p>RT\uFF08Response-time\uFF09\u54CD\u5E94\u65F6\u95F4\uFF1A\u6267\u884C\u4E00\u4E2A\u8BF7\u6C42\u4ECE\u5F00\u59CB\u5230\u6700\u540E\u6536\u5230\u54CD\u5E94\u6570\u636E\u6240\u82B1\u8D39\u7684\u603B\u4F53\u65F6\u95F4\uFF0C\u5373\u4ECE\u5BA2\u6237\u7AEF\u53D1\u8D77\u8BF7\u6C42\u5230\u6536\u5230\u670D\u52A1\u5668\u54CD\u5E94\u7ED3\u679C\u7684\u65F6\u95F4\u3002\u8BE5\u8BF7\u6C42\u53EF\u4EE5\u662F\u4EFB\u4F55\u4E1C\u897F\uFF0C\u4ECE\u5185\u5B58\u83B7\u53D6\uFF0C\u78C1\u76D8IO\uFF0C\u590D\u6742\u7684\u6570\u636E\u5E93\u67E5\u8BE2\u6216\u52A0\u8F7D\u5B8C\u6574\u7684\u7F51\u9875\u3002</p><p>\u6682\u65F6\u5FFD\u7565\u4F20\u8F93\u65F6\u95F4\uFF0C\u54CD\u5E94\u65F6\u95F4\u662F\u5904\u7406\u65F6\u95F4\u548C\u7B49\u5F85\u65F6\u95F4\u7684\u603B\u548C\u3002\u5904\u7406\u65F6\u95F4\u662F\u5B8C\u6210\u8BF7\u6C42\u8981\u6C42\u7684\u5DE5\u4F5C\u6240\u9700\u7684\u65F6\u95F4\uFF0C\u7B49\u5F85\u65F6\u95F4\u662F\u8BF7\u6C42\u5728\u88AB\u5904\u7406\u4E4B\u524D\u5FC5\u987B\u5728\u961F\u5217\u4E2D\u7B49\u5F85\u7684\u65F6\u95F4\u3002</p><p>\u54CD\u5E94\u65F6\u95F4\u662F\u4E00\u4E2A\u7CFB\u7EDF\u6700\u91CD\u8981\u7684\u6307\u6807\u4E4B\u4E00\uFF0C\u5B83\u7684\u6570\u503C\u5927\u5C0F\u76F4\u63A5\u53CD\u5E94\u4E86\u7CFB\u7EDF\u7684\u5FEB\u6162\u3002</p><h2 id="concurrency-\u5E76\u53D1\u6570" tabindex="-1"><a class="header-anchor" href="#concurrency-\u5E76\u53D1\u6570" aria-hidden="true">#</a> Concurrency\uFF0C\u5E76\u53D1\u6570</h2><p>\u5E76\u53D1\u6570\u662F\u6307\u7CFB\u7EDF\u540C\u65F6\u80FD\u5904\u7406\u7684\u8BF7\u6C42\u6570\u91CF\uFF0C\u8FD9\u4E2A\u4E5F\u53CD\u5E94\u4E86\u7CFB\u7EDF\u7684\u8D1F\u8F7D\u80FD\u529B\u3002</p><p>\u5E76\u53D1\u610F\u5473\u7740\u53EF\u4EE5\u540C\u65F6\u8FDB\u884C\u591A\u4E2A\u5904\u7406\u3002\u5E76\u53D1\u5728\u73B0\u4EE3\u7F16\u7A0B\u4E2D\u65E0\u5904\u4E0D\u5728\uFF0C\u7F51\u7EDC\u4E2D\u6709\u591A\u53F0\u8BA1\u7B97\u673A\u540C\u65F6\u5B58\u5728\uFF0C\u4E00\u53F0\u8BA1\u7B97\u673A\u4E0A\u540C\u65F6\u8FD0\u884C\u7740\u591A\u4E2A\u5E94\u7528\u7A0B\u5E8F\u3002</p><h2 id="\u541E\u5410\u91CF" tabindex="-1"><a class="header-anchor" href="#\u541E\u5410\u91CF" aria-hidden="true">#</a> \u541E\u5410\u91CF</h2><p>\u7CFB\u7EDF\u7684\u541E\u5410\u91CF\uFF08\u627F\u538B\u80FD\u529B\uFF09\u548C\u5904\u7406\u5BF9CPU\u7684\u6D88\u8017\u3001\u5916\u90E8\u63A5\u53E3\u3001IO\u7B49\u56E0\u7D20\u7D27\u5BC6\u5173\u8054\u3002\u5355\u4E2A\u5904\u7406\u8BF7\u6C42\u5BF9CPU\u6D88\u8017\u8D8A\u9AD8\uFF0C\u5916\u90E8\u7CFB\u7EDF\u63A5\u53E3\u3001IO\u901F\u5EA6\u8D8A\u6162\uFF0C\u7CFB\u7EDF\u541E\u5410\u80FD\u529B\u8D8A\u4F4E\uFF0C\u53CD\u4E4B\u8D8A\u9AD8\u3002</p><p>\u7CFB\u7EDF\u541E\u5410\u91CF\u6709\u51E0\u4E2A\u91CD\u8981\u6307\u6807\u53C2\u6570\uFF1AQPS\uFF08TPS\uFF09\u3001\u5E76\u53D1\u6570\u3001\u54CD\u5E94\u65F6\u95F4\u3002</p><ol><li>QPS\uFF08TPS\uFF09\uFF1A\uFF08Queries Per Second\uFF09\u6BCF\u79D2\u949F\u8BF7\u6C42/\u4E8B\u52A1\u6570\u91CF\u3002</li><li>\u5E76\u53D1\u6570\uFF1A \u7CFB\u7EDF\u540C\u65F6\u5904\u7406\u7684\u8BF7\u6C42/\u4E8B\u52A1\u6570\u3002</li><li>\u54CD\u5E94\u65F6\u95F4\uFF1A \u4E00\u822C\u53D6\u5E73\u5747\u54CD\u5E94\u65F6\u95F4\u3002</li></ol><blockquote><p>QPS\uFF08TPS\uFF09= \u5E76\u53D1\u6570/\u5E73\u5747\u54CD\u5E94\u65F6\u95F4<br> \u5E76\u53D1\u6570 = QPS*\u5E73\u5747\u54CD\u5E94\u65F6\u95F4</p></blockquote><h2 id="\u7ED3\u8BED" tabindex="-1"><a class="header-anchor" href="#\u7ED3\u8BED" aria-hidden="true">#</a> \u7ED3\u8BED</h2><p>\u6309\u4E8C\u516B\u5B9A\u5F8B\u6765\u770B\uFF0C\u5982\u679C\u6BCF\u5929 80% \u7684\u8BBF\u95EE\u96C6\u4E2D\u5728 20% \u7684\u65F6\u95F4\u91CC\uFF0C\u8FD9 20% \u7684\u65F6\u95F4\u5C31\u53EB\u505A\u5CF0\u503C\u65F6\u95F4\u3002</p><ul><li>\u516C\u5F0F\uFF1A( \u603BPV\u6570 * 80% ) / ( \u6BCF\u5929\u79D2\u6570 * 20% ) = \u5CF0\u503C\u65F6\u95F4\u6BCF\u79D2\u8BF7\u6C42\u6570(QPS)</li><li>\u673A\u5668\uFF1A\u5CF0\u503C\u65F6\u95F4\u6BCF\u79D2QPS / \u5355\u53F0\u673A\u5668\u7684QPS = \u9700\u8981\u7684\u673A\u5668</li></ul><ol><li>\u6BCF\u5929300w PV \u7684\u5728\u5355\u53F0\u673A\u5668\u4E0A\uFF0C\u8FD9\u53F0\u673A\u5668\u9700\u8981\u591A\u5C11QPS\uFF1F</li></ol><blockquote><p>( 3000000 * 0.8 ) / (86400 * 0.2 ) = 139 (QPS)</p></blockquote><ol start="2"><li>\u5982\u679C\u4E00\u53F0\u673A\u5668\u7684QPS\u662F58\uFF0C\u9700\u8981\u51E0\u53F0\u673A\u5668\u6765\u652F\u6301\uFF1F</li></ol><blockquote><p>139 / 58 = 3</p></blockquote><p>\u6700\u4F73\u7EBF\u7A0B\u6570\u3001QPS\u3001RT</p><ol><li>\u5355\u7EBF\u7A0BQPS\u516C\u5F0F\uFF1AQPS=1000ms/RT</li></ol><p>\u5BF9\u540C\u4E00\u4E2A\u7CFB\u7EDF\u800C\u8A00\uFF0C\u652F\u6301\u7684\u7EBF\u7A0B\u6570\u8D8A\u591A\uFF0CQPS\u8D8A\u9AD8\u3002\u5047\u8BBE\u4E00\u4E2ART\u662F80ms\uFF0C\u5219\u53EF\u4EE5\u5F88\u5BB9\u6613\u7684\u8BA1\u7B97\u51FAQPS\uFF0CQPS = 1000/80 = 12.5\u3002</p><p>\u591A\u7EBF\u7A0B\u573A\u666F\uFF0C\u5982\u679C\u628A\u670D\u52A1\u7AEF\u7684\u7EBF\u7A0B\u6570\u63D0\u5347\u52302\uFF0C\u90A3\u4E48\u6574\u4E2A\u7CFB\u7EDF\u7684QPS\u5219\u4E3A 2*\uFF081000/80\uFF09 = 25\uFF0C\u53EF\u89C1QPS\u968F\u7740\u7EBF\u7A0B\u7684\u589E\u52A0\u800C\u7EBF\u6027\u589E\u957F\uFF0C\u90A3QPS\u4E0A\u4E0D\u53BB\u5C31\u52A0\u7EBF\u7A0B\u5457\uFF0C\u542C\u8D77\u6765\u662F\u8FD9\u4E2A\u9053\u7406\uFF0C\u4F46\u662F\u5F80\u5F80\u73B0\u5B9E\u5E76\u975E\u5982\u6B64\u3002</p><ol start="2"><li>\u6700\u4F73\u7EBF\u7A0B\u6570\u91CF</li></ol><p>\u521A\u597D\u6D88\u8017\u5B8C\u670D\u52A1\u5668\u7684\u74F6\u9888\u8D44\u6E90\u7684\u4E34\u754C\u7EBF\u7A0B\u6570\uFF0C\u516C\u5F0F\u5982\u4E0B \u6700\u4F73\u7EBF\u7A0B\u6570\u91CF=\uFF08\uFF08\u7EBF\u7A0B\u7B49\u5F85\u65F6\u95F4+\u7EBF\u7A0Bcpu\u65F6\u95F4\uFF09/ \u7EBF\u7A0Bcpu\u65F6\u95F4\uFF09* cpu\u6570\u91CF</p><p>\u7279\u6027\uFF1A</p><ul><li>\u5728\u8FBE\u5230\u6700\u4F73\u7EBF\u7A0B\u6570\u7684\u65F6\u5019\uFF0C\u7EBF\u7A0B\u6570\u91CF\u7EE7\u7EED\u9012\u589E\uFF0C\u5219QPS\u4E0D\u53D8\uFF0C\u800C\u54CD\u5E94\u65F6\u95F4\u53D8\u957F\uFF0C\u6301\u7EED\u9012\u589E\u7EBF\u7A0B\u6570\u91CF\uFF0C\u5219QPS\u5F00\u59CB\u4E0B\u964D\u3002</li><li>\u6BCF\u4E2A\u7CFB\u7EDF\u90FD\u6709\u5176\u6700\u4F73\u7EBF\u7A0B\u6570\u91CF\uFF0C\u4F46\u662F\u4E0D\u540C\u72B6\u6001\u4E0B\uFF0C\u6700\u4F73\u7EBF\u7A0B\u6570\u91CF\u662F\u4F1A\u53D8\u5316\u7684\u3002</li><li>\u74F6\u9888\u8D44\u6E90\u53EF\u4EE5\u662FCPU\uFF0C\u53EF\u4EE5\u662F\u5185\u5B58\uFF0C\u53EF\u4EE5\u662F\u9501\u8D44\u6E90\uFF0CIO\u8D44\u6E90\uFF0C\u8D85\u8FC7\u6700\u4F73\u7EBF\u7A0B\u6570--&gt;\u5BFC\u81F4\u8D44\u6E90\u7684\u7ADE\u4E89\uFF0C\u8D85\u8FC7\u6700\u4F73\u7EBF\u7A0B\u6570--&gt;\u54CD\u5E94\u65F6\u95F4\u9012\u589E\u3002</li></ul>',33),c=[o];function p(t,n){return r(),a("div",null,c)}var d=e(l,[["render",p],["__file","high-concurrency.html.vue"]]);export{d as default};
